     1→/**
     2→ * Acceptance Test Kit — Shared Infrastructure
     3→ *
     4→ * Boots an in-process Brain server with isolated SurrealDB namespace.
     5→ * All acceptance test suites (core, orchestrator, intent, coding-session, etc.)
     6→ * build on this shared setup.
     7→ */
     8→import { afterAll, beforeAll } from "bun:test";
     9→import { randomBytes, createHash } from "node:crypto";
    10→import { readFileSync } from "node:fs";
    11→import { join } from "node:path";
    12→import { RecordId, Surreal } from "surrealdb";
    13→import * as jose from "jose";
    14→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
    15→import { createBrainServer } from "../../app/src/server/runtime/start-server";
    16→import { createRuntimeDependencies } from "../../app/src/server/runtime/dependencies";
    17→import { createSseRegistry } from "../../app/src/server/streaming/sse-registry";
    18→import { createInflightTracker } from "../../app/src/server/runtime/types";
    19→import { createNonceCache } from "../../app/src/server/oauth/nonce-cache";
    20→import type { ServerConfig } from "../../app/src/server/runtime/config";
    21→import type { ServerDependencies, InflightTracker } from "../../app/src/server/runtime/types";
    22→
    23→// ── Shared AI dependencies for standalone acceptance tests ──
    24→
    25→const openrouter = createOpenRouter({ apiKey: requireTestEnv("OPENROUTER_API_KEY") });
    26→
    27→export const testAI = {
    28→  openrouter,
    29→  extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
    30→  extractionModel: openrouter(requireTestEnv("EXTRACTION_MODEL")),
    31→  embeddingModel: openrouter.textEmbeddingModel(requireTestEnv("OPENROUTER_EMBEDDING_MODEL")),
    32→  embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
    33→};
    34→
    35→/** @deprecated Use `testAI` instead. */
    36→export const smokeAI = testAI;
    37→
    38→export type AcceptanceTestRuntime = {
    39→  baseUrl: string;
    40→  surreal: Surreal;
    41→  namespace: string;
    42→  database: string;
    43→  port: number;
    44→};
    45→
    46→/** @deprecated Use `AcceptanceTestRuntime` instead. */
    47→export type SmokeTestRuntime = AcceptanceTestRuntime;
    48→
    49→export type AcceptanceSuiteOptions = {
    50→  /** Extra env vars to set before the server boots (e.g. ORCHESTRATOR_MOCK_AGENT). */
    51→  env?: Record<string, string>;
    52→};
    53→
    54→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
    55→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
    56→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
    57→
    58→export function setupAcceptanceSuite(
    59→  suiteName: string,
    60→  options?: AcceptanceSuiteOptions,
    61→): () => AcceptanceTestRuntime {
    62→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
    63→  const namespace = `accept_${runId}`;
    64→  const suiteSlug = suiteName
    65→    .toLowerCase()
    66→    .replace(/[^a-z0-9]+/g, "_")
    67→    .replace(/^_+|_+$/g, "");
    68→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
    69→
    70→  let runtime: AcceptanceTestRuntime | undefined;
    71→  let server: ReturnType<typeof Bun.serve> | undefined;
    72→  let runtimeSurreal: Surreal | undefined;
    73→  let analyticsSurreal: Surreal | undefined;
    74→  let inflight: InflightTracker | undefined;
    75→  let setupSucceeded = false;
    76→
    77→  beforeAll(async () => {
    78→    // Apply env overrides before server boot
    79→    if (options?.env) {
    80→      for (const [k, v] of Object.entries(options.env)) {
    81→        process.env[k] = v;
    82→      }
    83→    }
    84→
    85→    const surreal = new Surreal();
    86→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
    87→    await withTimeout(
    88→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
    89→      10_000,
    90→      "authenticate with SurrealDB",
    91→    );
    92→
    93→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
    94→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
    95→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
    96→    await withTimeout(
    97→      () => surreal.use({ namespace, database }),
    98→      10_000,
    99→      "switch to test namespace/database",
   100→    );
   101→
   102→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
   103→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
   104→
   105→    // Reserve a port so betterAuth gets the real URL at init time
   106→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
   107→    const reservedPort = tempServer.port;
   108→    tempServer.stop(true);
   109→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
   110→
   111→    const config: ServerConfig = {
   112→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
   113→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
   114→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
   115→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
   116→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
   117→      embeddingModelId: requireTestEnv("OPENROUTER_EMBEDDING_MODEL"),
   118→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
   119→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
   120→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
   121→      surrealUrl,
   122→      surrealUsername,
   123→      surrealPassword,
   124→      surrealNamespace: namespace,
   125→      surrealDatabase: database,
   126→      port: reservedPort,
   127→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
   128→      betterAuthUrl: baseUrl,
   129→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
   130→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
   131→    };
   132→
   133→    const deps = await createRuntimeDependencies(config);
   134→    runtimeSurreal = deps.surreal;
   135→    analyticsSurreal = deps.analyticsSurreal;
   136→    inflight = createInflightTracker();
   137→
   138→    const serverDeps: ServerDependencies = {
   139→      config,
   140→      surreal: deps.surreal,
   141→      analyticsSurreal: deps.analyticsSurreal,
   142→      auth: deps.auth,
   143→      chatAgentModel: deps.chatAgentModel,
   144→      extractionModel: deps.extractionModel,
   145→      pmAgentModel: deps.pmAgentModel,
   146→      analyticsAgentModel: deps.analyticsAgentModel,
   147→      embeddingModel: deps.embeddingModel,
   148→      sse: createSseRegistry(),
   149→      inflight,
   150→      asSigningKey: deps.asSigningKey,
   151→      nonceCache: createNonceCache(),
   152→    };
   153→
   154→    server = createBrainServer(serverDeps);
   155→    const port = server.port;
   156→
   157→    runtime = { baseUrl, surreal, namespace, database, port };
   158→    setupSucceeded = true;
   159→  }, 60_000);
   160→
   161→  afterAll(async () => {
   162→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
   163→    if (inflight) {
   164→      await inflight.drain(15_000);
   165→    }
   166→
   167→    if (server) {
   168→      server.stop(true);
   169→    }
   170→
   171→    if (runtimeSurreal) {
   172→      await runtimeSurreal.close().catch(() => undefined);
   173→    }
   174→    if (analyticsSurreal) {
   175→      await analyticsSurreal.close().catch(() => undefined);
   176→    }
   177→
   178→    if (!runtime) {
   179→      return;
   180→    }
   181→
   182→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
   183→      try {
   184→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
   185→      } catch {
   186→        // Best effort cleanup.
   187→      }
   188→
   189→      try {
   190→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
   191→      } catch {
   192→        // Best effort cleanup.
   193→      }
   194→    }
   195→
   196→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
   197→  }, 20_000);
   198→
   199→  return () => {
   200→    if (!runtime) {
   201→      throw new Error("Acceptance runtime requested before suite setup completed");
   202→    }
   203→    return runtime;
   204→  };
   205→}
   206→
   207→/** @deprecated Use `setupAcceptanceSuite` instead. */
   208→export const setupSmokeSuite = setupAcceptanceSuite;
   209→
   210→// ---------------------------------------------------------------------------
   211→// Auth Helpers
   212→// ---------------------------------------------------------------------------
   213→
   214→export type TestUser = {
   215→  headers: Record<string, string>;
   216→};
   217→
   218→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
   219→  const email = `test-${Date.now()}-${suffix}@test.local`;
   220→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
   221→    method: "POST",
   222→    headers: { "Content-Type": "application/json" },
   223→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
   224→    redirect: "manual",
   225→  });
   226→
   227→  if (!response.ok) {
   228→    const body = await response.text();
   229→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
   230→  }
   231→
   232→  const setCookie = response.headers.getSetCookie();
   233→  if (!setCookie || setCookie.length === 0) {
   234→    throw new Error("Sign-up did not return session cookies");
   235→  }
   236→
   237→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
   238→  return { headers: { Cookie: cookieHeader } };
   239→}
