   316→// ---------------------------------------------------------------------------
   317→// OAuth Helpers
   318→// ---------------------------------------------------------------------------
   319→
   320→function base64url(buf: Buffer): string {
   321→  return buf.toString("base64url");
   322→}
   323→
   324→function generatePkce(): { verifier: string; challenge: string } {
   325→  const verifier = base64url(randomBytes(32));
   326→  const challenge = base64url(createHash("sha256").update(verifier).digest());
   327→  return { verifier, challenge };
   328→}
   329→
   330→/**
   331→ * Obtain an OAuth2 JWT access token for MCP endpoints.
   332→ * Requires a SurrealDB connection to skip consent screen.
   333→ */
   334→export async function getOAuthToken(
   335→  baseUrl: string,
   336→  surreal: Surreal,
   337→  sessionHeaders: Record<string, string>,
   338→  scopes: string = "graph:read graph:reason session:write offline_access",
   339→): Promise<string> {
   340→  // Trigger JWKS key generation if not yet done
   341→  await fetch(`${baseUrl}/api/auth/jwks`);
   342→
   343→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
   344→    method: "POST",
   345→    headers: { "Content-Type": "application/json" },
   346→    body: JSON.stringify({
   347→      client_name: `test-client-${Date.now()}`,
   348→      redirect_uris: ["http://127.0.0.1:9999/callback"],
   349→      grant_types: ["authorization_code", "refresh_token"],
   350→      response_types: ["code"],
   351→      token_endpoint_auth_method: "none",
   352→    }),
   353→  });
   354→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
   355→
   356→  const { client_id } = (await dcrRes.json()) as { client_id: string };
   357→
   358→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
   359→    cid: client_id,
   360→  });
   361→
   362→  const { verifier, challenge } = generatePkce();
   363→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
   364→  authUrl.searchParams.set("client_id", client_id);
   365→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
   366→  authUrl.searchParams.set("response_type", "code");
   367→  authUrl.searchParams.set("scope", scopes);
   368→  authUrl.searchParams.set("state", "test-state");
   369→  authUrl.searchParams.set("code_challenge", challenge);
   370→  authUrl.searchParams.set("code_challenge_method", "S256");
   371→  authUrl.searchParams.set("resource", baseUrl);
   372→
   373→  const authRes = await fetch(authUrl.toString(), {
   374→    headers: sessionHeaders,
   375→    redirect: "manual",
   376→  });
   377→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
   378→
   379→  const location = authRes.headers.get("location")!;
   380→  const redirectUrl = new URL(location, baseUrl);
   381→  const code = redirectUrl.searchParams.get("code") ?? "";
   382→  if (!code) throw new Error(`No code in redirect: ${location}`);
   383→
   384→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
   385→    method: "POST",
   386→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
   387→    body: new URLSearchParams({
   388→      grant_type: "authorization_code",
   389→      code,
   390→      redirect_uri: "http://127.0.0.1:9999/callback",
   391→      client_id,
   392→      code_verifier: verifier,
   393→      resource: baseUrl,
   394→    }),
   395→  });
   396→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
   397→
   398→  const tokens = (await tokenRes.json()) as { access_token: string };
   399→  return tokens.access_token;
   400→}
   401→
   402→export type DPoPKeyPair = {
   403→  privateKey: CryptoKey;
   404→  publicKey: CryptoKey;
   405→  publicJwk: JsonWebKey;
   406→  thumbprint: string;
   407→};
   408→
   409→export type TestUserWithMcp = TestUser & {
   410→  /** @deprecated Use mcpFetch instead — static Bearer headers are rejected by DPoP endpoints. */
   411→  mcpHeaders: Record<string, string>;
   412→  /** DPoP-protected fetch for MCP endpoints. Creates fresh proof per request. */
   413→  mcpFetch: (path: string, options?: { method?: string; body?: unknown }) => Promise<Response>;
   414→  accessToken: string;
   415→  keyPair: DPoPKeyPair;
   416→};
   417→
   418→/**
   419→ * Create a test user with DPoP-bound token for MCP endpoints.
   420→ * Generates key pair, creates identity, seeds broad-access intent, acquires token.
   421→ */
   422→export async function createTestUserWithMcp(
   423→  baseUrl: string,
   424→  surreal: Surreal,
   425→  suffix: string,
   426→): Promise<TestUserWithMcp> {
   427→  const user = await createTestUser(baseUrl, suffix);
   428→
   429→  // Generate DPoP key pair
   430→  const keyPair = await generateDPoPKeyPair();
   431→
   432→  // Create identity record for this user
   433→  const identityId = `test-identity-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
   434→  const identityRecord = new RecordId("identity", identityId);
   435→
   436→  // Find the workspace for this user (or create a temporary one)
   437→  // For broad test access, create an identity in the DB
   438→  await surreal.query(`CREATE $identity CONTENT $content;`, {
   439→    identity: identityRecord,
   440→    content: {
   441→      name: `Test User ${suffix}`,
   442→      type: "agent",
   443→      identity_status: "active",
   444→      created_at: new Date(),
   445→    },
   446→  });
   447→
   448→  // Seed a broad-access authorized intent covering all MCP operations
   449→  const broadActions = [
   450→    { type: "brain_action", action: "read", resource: "workspace" },
   451→    { type: "brain_action", action: "read", resource: "project" },
   452→    { type: "brain_action", action: "read", resource: "task" },
   453→    { type: "brain_action", action: "read", resource: "decision" },
   454→    { type: "brain_action", action: "read", resource: "constraint" },
   455→    { type: "brain_action", action: "read", resource: "change_log" },
   456→    { type: "brain_action", action: "read", resource: "entity" },
   457→    { type: "brain_action", action: "read", resource: "suggestion" },
   458→    { type: "brain_action", action: "read", resource: "intent" },
   459→    { type: "brain_action", action: "reason", resource: "decision" },
   460→    { type: "brain_action", action: "reason", resource: "constraint" },
   461→    { type: "brain_action", action: "reason", resource: "commit" },
   462→    { type: "brain_action", action: "create", resource: "decision" },
   463→    { type: "brain_action", action: "create", resource: "question" },
   464→    { type: "brain_action", action: "create", resource: "task" },
   465→    { type: "brain_action", action: "create", resource: "note" },
   466→    { type: "brain_action", action: "create", resource: "observation" },
   467→    { type: "brain_action", action: "create", resource: "suggestion" },
   468→    { type: "brain_action", action: "create", resource: "session" },
   469→    { type: "brain_action", action: "create", resource: "commit" },
   470→    { type: "brain_action", action: "create", resource: "intent" },
   471→    { type: "brain_action", action: "update", resource: "task" },
   472→    { type: "brain_action", action: "update", resource: "session" },
   473→    { type: "brain_action", action: "update", resource: "suggestion" },
   474→    { type: "brain_action", action: "submit", resource: "intent" },
   475→  ];
   476→
   477→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
   478→  const intentRecord = new RecordId("intent", intentId);
   479→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
   480→
   481→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
   482→    trace: traceRecord,
   483→    traceContent: { type: "test_setup", actor: identityRecord, created_at: new Date() },
   484→  });
   485→
   486→  await surreal.query(`CREATE $intent CONTENT $content;`, {
   487→    intent: intentRecord,
   488→    content: {
   489→      goal: "Broad test access",
   490→      reasoning: "Pre-authorized for acceptance testing",
   491→      status: "authorized",
   492→      priority: 50,
   493→      authorization_details: broadActions,
   494→      dpop_jwk_thumbprint: keyPair.thumbprint,
   495→      action_spec: { provider: "test", action: "broad_access", params: {} },
   496→      trace_id: traceRecord,
   497→      requester: identityRecord,
   498→      evaluation: {
   499→        decision: "APPROVE",
   500→        risk_score: 0,
   501→        reason: "Pre-authorized for testing",
   502→        evaluated_at: new Date(),
   503→        policy_only: true,
   504→      },
   505→      created_at: new Date(),
   506→    },
   507→  });
   508→
   509→  // Request DPoP-bound access token from Custom AS
   510→  const tokenUri = `${baseUrl}/api/auth/token`;
   511→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
   512→
   513→  const tokenRes = await fetch(tokenUri, {
   514→    method: "POST",
   515→    headers: {
   516→      "Content-Type": "application/json",
   517→      DPoP: dpopProof,
   518→    },
   519→    body: JSON.stringify({
   520→      grant_type: "urn:brain:intent-authorization",
   521→      intent_id: intentId,
   522→      authorization_details: broadActions,
   523→    }),
   524→  });
   525→
   526→  if (!tokenRes.ok) {
   527→    const body = await tokenRes.text();
   528→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
   529→  }
   530→
   531→  const { access_token } = (await tokenRes.json()) as { access_token: string };
   532→
   533→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
   534→    const method = options?.method ?? "POST";
   535→    const requestUri = `${baseUrl}${path}`;
   536→    const proof = await createDPoPProof(keyPair, method, requestUri);
   537→
   538→    return fetch(requestUri, {
   539→      method,
   540→      headers: {
   541→        "Content-Type": "application/json",
   542→        Authorization: `DPoP ${access_token}`,
   543→        DPoP: proof,
   544→      },
   545→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
   546→    });
   547→  };
   548→
   549→  return {
   550→    ...user,
   551→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
   552→    mcpFetch,
   553→    accessToken: access_token,
   554→    keyPair,
   555→  };
   556→}
   557→
   558→// ---------------------------------------------------------------------------
   559→// DPoP Helpers
   560→// ---------------------------------------------------------------------------
   561→
   562→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
   563→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
   564→    { name: "ECDSA", namedCurve: "P-256" },
   565→    true,
   566→    ["sign", "verify"],
   567→  );
   568→
   569→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
   570→  const thumbprint = await computeDPoPThumbprint(publicJwk);
   571→
   572→  return { privateKey, publicKey, publicJwk, thumbprint };
   573→}
   574→
   575→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
   576→  const thumbprintInput = JSON.stringify({
   577→    crv: publicJwk.crv,
   578→    kty: publicJwk.kty,
   579→    x: publicJwk.x,
   580→    y: publicJwk.y,
   581→  });
   582→
   583→  const hashBuffer = await crypto.subtle.digest(
   584→    "SHA-256",
   585→    new TextEncoder().encode(thumbprintInput),
   586→  );
   587→
   588→  return base64urlBytes(new Uint8Array(hashBuffer));
   589→}
   590→
   591→async function createDPoPProof(
   592→  keyPair: DPoPKeyPair,
   593→  method: string,
   594→  targetUri: string,
   595→): Promise<string> {
   596→  const header = {
   597→    typ: "dpop+jwt" as const,
   598→    alg: "ES256" as const,
   599→    jwk: {
   600→      kty: keyPair.publicJwk.kty,
   601→      crv: keyPair.publicJwk.crv,
   602→      x: keyPair.publicJwk.x,
   603→      y: keyPair.publicJwk.y,
   604→    },
   605→  };
   606→
   607→  const payload = {
   608→    jti: crypto.randomUUID(),
   609→    htm: method,
   610→    htu: targetUri,
   611→    iat: Math.floor(Date.now() / 1000),
   612→  };
   613→
   614→  const importedKey = await jose.importJWK(
   615→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
   616→    "ES256",
   617→  );
   618→
   619→  return await new jose.SignJWT(payload)
   620→    .setProtectedHeader(header)
   621→    .sign(importedKey);
   622→}
   623→
   624→function base64urlBytes(bytes: Uint8Array): string {
   625→  const binary = String.fromCharCode(...bytes);
   626→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
   627→}
   628→
   629→// ---------------------------------------------------------------------------
   630→// Internal Utilities
   631→// ---------------------------------------------------------------------------
   632→
   633→function requireTestEnv(name: string): string {
   634→  const value = process.env[name];
   635→  if (!value || value.trim().length === 0) {
   636→    throw new Error(`Acceptance test requires env var ${name}`);
   637→  }
   638→  return value;
   639→}
   640→
   641→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
   642→  return await Promise.race([
   643→    callback(),
   644→    new Promise<T>((_, reject) => {
   645→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
   646→    }),
   647→  ]);
   648→}
