     1→/**
     2→ * Bridge Session-to-Token Exchange
     3→ *
     4→ * POST /api/auth/bridge/exchange accepting Better Auth session cookie +
     5→ * DPoP proof + authorization_details. Validates session, resolves human
     6→ * identity, creates implicit intent, evaluates via pipeline, issues
     7→ * DPoP-bound token.
     8→ *
     9→ * Pure validation functions + HTTP handler factory.
    10→ *
    11→ * Step: 04-01
    12→ */
    13→import { RecordId, type Surreal } from "surrealdb";
    14→import type { BrainAction } from "./types";
    15→import type { ServerDependencies } from "../runtime/types";
    16→import { validateDPoPProof } from "./dpop";
    17→import { issueAccessToken } from "./token-issuer";
    18→import { createIntent, createTrace, updateIntentStatus, recordTokenIssuance } from "../intent/intent-queries";
    19→import {
    20→  isLowRiskReadAction,
    21→  deriveActionSpec,
    22→  validateBrainActionEntry,
    23→} from "./intent-submission";
    24→import { evaluateIntent, createLlmEvaluator } from "../intent/authorizer";
    25→import { routeByRisk } from "../intent/risk-router";
    26→import { jsonResponse } from "../http/response";
    27→import { logError, logInfo } from "../http/observability";
    28→import { logAuditEvent, createAuditEvent } from "./audit";
    29→import { oauthErrorResponse } from "./oauth-errors";
    30→
    31→// ---------------------------------------------------------------------------
    32→// Types
    33→// ---------------------------------------------------------------------------
    34→
    35→export type BridgeExchangeInput = {
    36→  authorizationDetails: BrainAction[];
    37→};
    38→
    39→type BridgeValidation =
    40→  | { valid: true; data: BridgeExchangeInput }
    41→  | { valid: false; error: string };
    42→
    43→// ---------------------------------------------------------------------------
    44→// Pure Validation: Request Body
    45→// ---------------------------------------------------------------------------
    46→
    47→export function validateBridgeExchangeRequest(body: unknown): BridgeValidation {
    48→  if (!body || typeof body !== "object") {
    49→    return { valid: false, error: "Request body must be a non-null object" };
    50→  }
    51→
    52→  const input = body as Record<string, unknown>;
    53→
    54→  if (!Array.isArray(input.authorization_details)) {
    55→    return {
    56→      valid: false,
    57→      error: "authorization_details is required and must be an array",
    58→    };
    59→  }
    60→
    61→  if (input.authorization_details.length === 0) {
    62→    return {
    63→      valid: false,
    64→      error: "authorization_details must contain at least one entry",
    65→    };
    66→  }
    67→
    68→  for (let i = 0; i < input.authorization_details.length; i++) {
    69→    const entry = input.authorization_details[i] as Record<string, unknown>;
    70→    const validationError = validateBrainActionEntry(entry, i);
    71→    if (validationError) {
    72→      return { valid: false, error: validationError };
    73→    }
    74→  }
    75→
    76→  return {
    77→    valid: true,
    78→    data: {
    79→      authorizationDetails: input.authorization_details as BrainAction[],
    80→    },
    81→  };
    82→}
    83→
    84→// ---------------------------------------------------------------------------
    85→// Identity + Workspace Resolution
    86→// ---------------------------------------------------------------------------
    87→
    88→type HumanContext = {
    89→  identityId: string;
    90→  workspaceId: string;
    91→};
    92→
    93→/**
    94→ * Resolves a person's identity and primary workspace via graph traversal.
    95→ * person -> identity_person -> identity -> member_of -> workspace
    96→ */
    97→async function resolveHumanContext(
    98→  surreal: Surreal,
    99→  personId: string,
   100→): Promise<HumanContext | undefined> {
   101→  const person = new RecordId("person", personId);
   102→
   103→  // Step 1: person -> identity via identity_person spoke
   104→  const [identityRows] = await surreal.query<[Array<RecordId<"identity", string>>]>(
   105→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
   106→    { person },
   107→  );
   108→  if (!identityRows || identityRows.length === 0) return undefined;
   109→
   110→  const identityRecord = identityRows[0];
   111→  const identityId = identityRecord.id as string;
   112→
   113→  // Step 2: identity -> workspace via member_of edge
   114→  const [workspaceRows] = await surreal.query<[Array<{ out: RecordId<"workspace", string> }>]>(
   115→    "SELECT out FROM member_of WHERE in = $identity LIMIT 1;",
   116→    { identity: identityRecord },
   117→  );
   118→  if (!workspaceRows || workspaceRows.length === 0) return undefined;
   119→
   120→  const workspaceId = workspaceRows[0].out.id as string;
   121→
   122→  return { identityId, workspaceId };
   123→}
   124→
   125→// ---------------------------------------------------------------------------
   126→// HTTP Handler Factory
   127→// ---------------------------------------------------------------------------
   128→
   129→export function createBridgeExchangeHandler(
   130→  deps: ServerDependencies,
   131→): (request: Request) => Promise<Response> {
   132→  const { surreal, auth, asSigningKey } = deps;
   133→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
   134→
   135→  return async (request: Request): Promise<Response> => {
   136→    // 1. Validate session via Better Auth
   137→    const session = await auth.api.getSession({ headers: request.headers });
   138→    if (!session?.user?.id) {
   139→      return oauthErrorResponse(
   140→        "invalid_session",
   141→        "Valid session required",
   142→        401,
   143→      );
   144→    }
   145→
   146→    const personId = session.user.id;
   147→
   148→    // 2. Extract and validate DPoP proof
   149→    const dpopHeader = request.headers.get("DPoP");
   150→    if (!dpopHeader) {
   151→      return oauthErrorResponse(
   152→        "invalid_request",
   153→        "DPoP proof required",
   154→        400,
   155→      );
   156→    }
   157→
   158→    const requestUrl = new URL(request.url);
   159→    const dpopResult = await validateDPoPProof(
   160→      dpopHeader,
   161→      "POST",
   162→      `${requestUrl.origin}/api/auth/bridge/exchange`,
   163→    );
   164→
   165→    if (!dpopResult.valid) {
   166→      return oauthErrorResponse("invalid_dpop_proof", dpopResult.error, 400);
   167→    }
   168→
   169→    // 3. Parse and validate request body
   170→    let body: unknown;
   171→    try {
   172→      body = await request.json();
   173→    } catch {
   174→      return oauthErrorResponse("invalid_request", "Invalid JSON body", 400);
   175→    }
   176→
   177→    const validation = validateBridgeExchangeRequest(body);
   178→    if (!validation.valid) {
   179→      return oauthErrorResponse("invalid_request", validation.error, 400);
   180→    }
   181→
   182→    const { authorizationDetails } = validation.data;
   183→
   184→    // 4. Resolve human identity and workspace from person
   185→    const humanContext = await resolveHumanContext(surreal, personId);
   186→    if (!humanContext) {
   187→      return oauthErrorResponse(
   188→        "invalid_session",
   189→        "No identity found for session user",
   190→        401,
   191→      );
   192→    }
   193→
   194→    const { identityId, workspaceId } = humanContext;
   195→    const requester = new RecordId("identity", identityId);
   196→    const workspace = new RecordId("workspace", workspaceId);
   197→
   198→    try {
   199→      // 5. Create trace + implicit intent
   200→      const actionSpec = deriveActionSpec(authorizationDetails);
   201→
   202→      const traceRecord = await createTrace(surreal, {
   203→        type: "bridge_exchange",
   204→        actor: requester,
   205→        workspace,
   206→        input: { authorization_details: authorizationDetails, source: "bridge_exchange" },
   207→      });
   208→
   209→      const intentRecord = await createIntent(surreal, {
   210→        goal: `Bridge exchange: ${authorizationDetails.map((a) => `${a.action} ${a.resource}`).join(", ")}`,
   211→        reasoning: "Implicit intent created by bridge session-to-token exchange",
   212→        priority: 0,
   213→        action_spec: actionSpec,
   214→        trace_id: traceRecord,
   215→        requester,
   216→        workspace,
   217→        authorization_details: authorizationDetails,
   218→        dpop_jwk_thumbprint: dpopResult.thumbprint,
   219→      });
   220→
   221→      const intentId = intentRecord.id as string;
   222→
   223→      await logAuditEvent(surreal, createAuditEvent("intent_submitted", {
   224→        actor: new RecordId("identity", identityId),
   225→        workspace: new RecordId("workspace", workspaceId),
   226→        intent_id: intentRecord,
   227→        dpop_thumbprint: dpopResult.thumbprint,
   228→        payload: {
   229→          source: "bridge_exchange",
   230→          authorization_details: authorizationDetails,
   231→        },
   232→      })).catch(() => {});
   233→
   234→      // 6. Transition to pending_auth
   235→      await updateIntentStatus(surreal, intentId, "pending_auth");
   236→
   237→      // 7. Evaluate intent
   238→      const isLowRisk = isLowRiskReadAction(authorizationDetails);
   239→
   240→      const evaluation = await evaluateIntent({
   241→        intent: {
   242→          goal: `Bridge exchange: ${authorizationDetails[0].action} ${authorizationDetails[0].resource}`,
   243→          reasoning: "Human operator bridge exchange",
   244→          action_spec: actionSpec,
   245→          requester: identityId,
   246→        },
   247→        policy: {},
   248→        llmEvaluator,
   249→        timeoutMs: 10_000,
   250→      });
   251→
   252→      const routing = routeByRisk(evaluation);
   253→      const evaluationRecord = {
   254→        ...evaluation,
   255→        evaluated_at: new Date(),
   256→      };
   257→
   258→      // 8. Route by risk
   259→      if (routing.route === "reject") {
   260→        await updateIntentStatus(surreal, intentId, "failed", {
   261→          evaluation: evaluationRecord,
   262→          error_reason: routing.reason,
   263→        });
   264→
   265→        await logAuditEvent(surreal, createAuditEvent("token_rejected", {
   266→          actor: new RecordId("identity", identityId),
   267→          workspace: new RecordId("workspace", workspaceId),
   268→          intent_id: new RecordId("intent", intentId),
   269→          dpop_thumbprint: dpopResult.thumbprint,
   270→          payload: { reason: routing.reason, route: "reject" },
   271→        })).catch(() => {});
   272→
   273→        return oauthErrorResponse(
   274→          "access_denied",
   275→          routing.reason,
   276→          403,
   277→        );
   278→      }
   279→
   280→      if (routing.route === "veto_window" && !isLowRisk) {
   281→        await updateIntentStatus(surreal, intentId, "pending_veto", {
   282→          evaluation: evaluationRecord,
   283→          veto_expires_at: routing.expires_at,
   284→        });
   285→
   286→        return jsonResponse(
   287→          {
   288→            status: "pending_veto",
   289→            intent_id: intentId,
   290→            veto_expires_at: routing.expires_at.toISOString(),
   291→          },
   292→          202,
   293→        );
   294→      }
   295→
   296→      // 9. Auto-approve: authorize intent and issue token
   297→      await updateIntentStatus(surreal, intentId, "authorized", {
   298→        evaluation: evaluationRecord,
   299→      });
   300→
   301→      logInfo("bridge.exchange.authorized", "Bridge intent auto-approved", {
   302→        intentId,
   303→      });
   304→
   305→      // 10. Issue DPoP-bound token
   306→      const tokenResult = await issueAccessToken(asSigningKey, {
