   309→        authorizationDetails,
   310→        intentId,
   311→        workspace: workspaceId,
   312→        actorType: "human",
   313→      });
   314→
   315→      if (!tokenResult.ok) {
   316→        return oauthErrorResponse("server_error", tokenResult.error, 500);
   317→      }
   318→
   319→      // 11. Update intent with token timestamps
   320→      const now = new Date();
   321→      await recordTokenIssuance(surreal, intentId, now, tokenResult.expiresAt)
   322→        .catch((err) => {
   323→          logError("bridge.exchange.update_intent", "Failed to update intent with token timestamps", err);
   324→        });
   325→
   326→      await logAuditEvent(surreal, createAuditEvent("token_issued", {
   327→        actor: new RecordId("identity", identityId),
   328→        workspace: new RecordId("workspace", workspaceId),
   329→        intent_id: intentRecord,
   330→        dpop_thumbprint: dpopResult.thumbprint,
