   619→    constraints: taskId ? { task_id: taskId } : undefined,
   620→  };
   621→}
   622→
   623→/**
   624→ * Creates a brain_action for creating a new decision.
   625→ */
   626→export function createDecisionAction(): BrainAction {
   627→  return {
   628→    type: "brain_action",
   629→    action: "create",
   630→    resource: "decision",
   631→  };
   632→}
   633→
   634→/**
   635→ * Waits for an intent to reach a target status by polling the database.
   636→ */
   637→export async function waitForIntentStatus(
   638→  surreal: Surreal,
   639→  intentId: string,
   640→  targetStatuses: string[],
   641→  timeoutMs = 30_000,
   642→): Promise<string> {
   643→  const intentRecord = new RecordId("intent", intentId);
   644→  const start = Date.now();
   645→
   646→  while (Date.now() - start < timeoutMs) {
   647→    const rows = (await surreal.query(`SELECT status FROM $intent;`, {
   648→      intent: intentRecord,
   649→    })) as Array<Array<{ status: string }>>;
   650→
   651→    const status = rows[0]?.[0]?.status;
   652→    if (status && targetStatuses.includes(status)) {
   653→      return status;
   654→    }
   655→
   656→    await Bun.sleep(250);
   657→  }
   658→
   659→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
   660→    intent: intentRecord,
   661→  })) as Array<Array<{ status: string }>>;
   662→
   663→  throw new Error(
   664→    `Intent ${intentId} did not reach ${targetStatuses.join("|")} within ${timeoutMs}ms. ` +
   665→    `Current status: ${rows[0]?.[0]?.status ?? "not found"}`,
   666→  );
   667→}
   668→
   669→// ---------------------------------------------------------------------------
   670→// Internal Utilities
   671→// ---------------------------------------------------------------------------
   672→
   673→function base64url(bytes: Uint8Array): string {
   674→  const binary = String.fromCharCode(...bytes);
   675→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
   676→}
